void processCommandLine(string command, Configuration& config) {
    if (command.empty()) {
        return;
    }

    // Split command into parts
    vector<string> parts = {};
    size_t i = 0;
    while (i < command.length()) {
        if (command[i] == ' ') {
            parts.push_back(command.substr(i));
            i++;
        } else if (command[i] == ',') {
            parts.push_back(command.substr(i));
            i++;
        } else {
            i++;
        }
    }

    if (parts.size() < 2) {
        return;
    }

    string action = parts[0];
    string details = parts.size() > 1 ? parts[1] : "";

    if (action == "set") {
        if (details.size() < 2) {
            return;
        }
        string key = details.substr(0, 1);
        string value = details.substr(2);
        config.set(key, value);
    } else if (action == "display") {
        config.display();
    } else if (action == "reset") {
        config.reset();
    }
}

int main() {
    Configuration config;
    processCommandLine("set,key,value", config);
    processCommandLine("display", config);
    processCommandLine("reset", config);
    return 0;
}

