class Permission {
public:
    std::string name;
    std::map<std::string, Permission*> children;
    bool isRoot;

    Permission(const std::string& name) : name(name), isRoot(true) {}

    void addChild(const std::string& childName, Permission* child) {
        children[childName] = child;
    }

    void removeChild(const std::string& childName) {
        if (children.find(childName) != children.end()) {
            children.erase(childName);
        }
    }

    void updateChild(const std::string& childName, Permission* newChild) {
        if (children.find(childName) != children.end()) {
            children[childName] = newChild;
        }
    }

    void addPermission(const std::string& name) {
        if (!isRoot) {
            throw std::runtime_error("Cannot add permission to a non-root node");
        }
        Permission* newPerm = new Permission(name);
        children[name] = newPerm;
    }

    void removePermission(const std::string& name) {
        if (!isRoot) {
            throw std::runtime_error("Cannot remove permission from a non-root node");
        }
        if (children.find(name) != children.end()) {
            children.erase(name);
        }
    }

    void updatePermission(const std::string& name, const std::string& newName) {
        if (!isRoot) {
            throw std::runtime_error("Cannot update permission from a non-root node");
        }
        if (children.find(name) != children.end()) {
            children[name].name = newName;
        }
    }

    void printPermissions() const {
        if (isRoot) {
            std::cout << "Root Permissions:\n";
            for (const auto& pair : children) {
                std::cout << "  " << pair.first << "\n";
                pair.second->printPermissions();
            }
        }
    }
};

