fn process_grid_operations(matrix: Vec<Vec<i32>>, operations: Vec<String>) -> Vec<Vec<i32>> {
    let mut grid = matrix;
    for op in operations {
        match op.as_str() {
            "rotate" => {
                // Rotate 90 degrees clockwise
                let mut new_grid = Vec::new();
                for i in 0..grid.len() {
                    let mut row = Vec::new();
                    for j in 0..grid[i].len() {
                        row.push(grid[j][grid.len() - 1 - i]);
                    }
                    new_grid.push(row);
                }
                grid = new_grid;
            }
            "flip" => {
                // Flip horizontally
                let mut new_grid = Vec::new();
                for i in 0..grid.len() {
                    let mut row = Vec::new();
                    for j in 0..grid[i].len() {
                        row.push(grid[i][grid[i].len() - 1 - j]);
                    }
                    new_grid.push(row);
                }
                grid = new_grid;
            }
            "invert" => {
                // Invert values (0 <-> 1)
                let mut new_grid = Vec::new();
                for i in 0..grid.len() {
                    let mut row = Vec::new();
                    for j in 0..grid[i].len() {
                        row.push(1 - grid[i][j]);
                    }
                    new_grid.push(row);
                }
                grid = new_grid;
            }
            _ => {}
        }
    }
    grid
}

