    let image = match image::Image::from_data(image_data) {
        Ok(img) => img,
        Err(e) => return Err(format!("Failed to decode image: {}", e)),
    };

    // Apply grayscale filter
    let grayscale_image = image::RgbImage::from_pixel_data(
        image.width() as u32,
        image.height() as u32,
        image.data().iter().map(|pixel| {
