            let g = pixel.0.1;
            let b = pixel.0.2;
            (r as u8 + g as u8 + b as u8) / 3
        })
    );

    // Re-encode the image into the specified format
    let encoded_image = match image::Image::from_data(grayscale_image.to_rgba8()) {
        Ok(img) => img,
        Err(e) => return Err(format!("Failed to encode image: {}", e)),
    };

    // Save the encoded image to a file and return the byte data
    let mut file = File::create("encoded_image.jpg")?;
    encoded_image.write_to(file, ImageFormat::Jpeg)?;
    Ok(file.into_inner().unwrap().to_vec())
