public class MatrixTransformer {
    public static int[][] transformMatrix(int[][] matrix, String operationMode) {
        int rows = matrix.length;
        int cols = matrix[0].length;

        int[][] transformed = new int[rows][cols];

        if (operationMode.equals("rotate_left")) {
            for (int i = 0; i < rows; i++) {
                for (int j = 0; j < cols; j++) {
                    transformed[j][rows - 1 - i] = matrix[i][j];
                }
            }
        } else if (operationMode.equals("rotate_right")) {
            for (int i = 0; i < rows; i++) {
                for (int j = 0; j < cols; j++) {
                    transformed[rows - 1 - j][i] = matrix[i][j];
                }
            }
        } else if (operationMode.equals("flip_vertical")) {
            for (int i = 0; i < rows / 2; i++) {
                for (int j = 0; j < cols; j++) {
                    transformed[i][j] = matrix[rows - 1 - i][j];
                    transformed[rows - 1 - i][j] = matrix[i][j];
                }
            }
        } else if (operationMode.equals("flip_horizontal")) {
            for (int i = 0; i < rows; i++) {
                for (int j = 0; j < cols / 2; j++) {
                    int temp = matrix[i][j];
                    matrix[i][j] = matrix[i][cols - 1 - j];
                    matrix[i][cols - 1 - j] = temp;
                }
            }
        }

        return transformed;
    }
}

